def gen(rng, size):
    n = max(1, min(400, size))
    grid = [[1 if rng.random() < 0.03 else 0 for _ in range(n)] for _ in range(n)]
    if not any(1 in row for row in grid):
        grid[rng.randrange(n)][rng.randrange(n)] = 1
    return [grid]

