class Solution:
    def maximumSafenessFactor(self, grid):
        from collections import deque
        n = len(grid)
        dist = [[-1] * n for _ in range(n)]
        dq = deque()
        for r in range(n):
            for c in range(n):
                if grid[r][c] == 1:
                    dist[r][c] = 0
                    dq.append((r, c))
        while dq:
            r, c = dq.popleft()
            for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                nr, nc = r + dr, c + dc
                if 0 <= nr < n and 0 <= nc < n and dist[nr][nc] == -1:
                    dist[nr][nc] = dist[r][c] + 1
                    dq.append((nr, nc))

        def reachable(v):
            if dist[0][0] < v or dist[n - 1][n - 1] < v:
                return False
            seen = [[False] * n for _ in range(n)]
            seen[0][0] = True
            stack = [(0, 0)]
            while stack:
                r, c = stack.pop()
                if r == n - 1 and c == n - 1:
                    return True
                for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < n and 0 <= nc < n and not seen[nr][nc] and dist[nr][nc] >= v:
                        seen[nr][nc] = True
                        stack.append((nr, nc))
            return False

        lo, hi, ans = 0, 2 * n, 0
        while lo <= hi:
            mid = (lo + hi) // 2
            if reachable(mid):
                ans = mid
                lo = mid + 1
            else:
                hi = mid - 1
        return ans

