class Solution:
    def maximumSafenessFactor(self, grid):
        from collections import deque
        import heapq
        n = len(grid)
        dist = [[-1] * n for _ in range(n)]
        dq = deque()
        for r in range(n):
            for c in range(n):
                if grid[r][c] == 1:
                    dist[r][c] = 0
                    dq.append((r, c))
        while dq:
            r, c = dq.popleft()
            for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                nr, nc = r + dr, c + dc
                if 0 <= nr < n and 0 <= nc < n and dist[nr][nc] == -1:
                    dist[nr][nc] = dist[r][c] + 1
                    dq.append((nr, nc))
        best = [[-1] * n for _ in range(n)]
        best[0][0] = dist[0][0]
        heap = [(-dist[0][0], 0, 0)]
        while heap:
            negval, r, c = heapq.heappop(heap)
            val = -negval
            if val < best[r][c]:
                continue
            if r == n - 1 and c == n - 1:
                return val
            for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                nr, nc = r + dr, c + dc
                if 0 <= nr < n and 0 <= nc < n:
                    cand = min(val, dist[nr][nc])
                    if cand > best[nr][nc]:
                        best[nr][nc] = cand
                        heapq.heappush(heap, (-cand, nr, nc))
        return best[n - 1][n - 1]

