var maximumSafenessFactor = function(grid) {
    const n = grid.length;
    const dist = Array.from({ length: n }, () => new Array(n).fill(-1));
    const queue = [];
    for (let r = 0; r < n; r++) {
        for (let c = 0; c < n; c++) {
            if (grid[r][c] === 1) { dist[r][c] = 0; queue.push([r, c]); }
        }
    }
    const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];
    let qi = 0;
    while (qi < queue.length) {
        const [r, c] = queue[qi++];
        for (const [dr, dc] of dirs) {
            const nr = r + dr, nc = c + dc;
            if (nr >= 0 && nr < n && nc >= 0 && nc < n && dist[nr][nc] === -1) {
                dist[nr][nc] = dist[r][c] + 1;
                queue.push([nr, nc]);
            }
        }
    }
    const best = Array.from({ length: n }, () => new Array(n).fill(-1));
    best[0][0] = dist[0][0];
    const heap = [];
    function push(val, r, c) {
        heap.push([val, r, c]);
        let i = heap.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (heap[p][0] < heap[i][0]) { const t = heap[p]; heap[p] = heap[i]; heap[i] = t; i = p; }
            else break;
        }
    }
    function pop() {
        const top = heap[0];
        const last = heap.pop();
        if (heap.length > 0) {
            heap[0] = last;
            let i = 0;
            while (true) {
                const l = 2 * i + 1, r = 2 * i + 2;
                let largest = i;
                if (l < heap.length && heap[l][0] > heap[largest][0]) largest = l;
                if (r < heap.length && heap[r][0] > heap[largest][0]) largest = r;
                if (largest === i) break;
                const t = heap[largest]; heap[largest] = heap[i]; heap[i] = t;
                i = largest;
            }
        }
        return top;
    }
    push(dist[0][0], 0, 0);
    while (heap.length) {
        const [val, r, c] = pop();
        if (val < best[r][c]) continue;
        if (r === n - 1 && c === n - 1) return val;
        for (const [dr, dc] of dirs) {
            const nr = r + dr, nc = c + dc;
            if (nr >= 0 && nr < n && nc >= 0 && nc < n) {
                const cand = Math.min(val, dist[nr][nc]);
                if (cand > best[nr][nc]) { best[nr][nc] = cand; push(cand, nr, nc); }
            }
        }
    }
    return best[n - 1][n - 1];
};
